mapper.select:
select id, code, name, username_unique as usernameUnique, email_unique as emailUnique, mobile_unique as mobileUnique, case_sensitive as caseSensitive, allow_email_reuse as allowEmailReuse, allow_mobile_reuse as allowMobileReuse, status, description, create_time, update_time from unique_policy
and `name` like concat('%', #{request.name}, '%')
and `code` = #{request.code}
and `status` = #{request.status}
order by create_time desc
